parameters.text:
=You are a professional email writer. Generate a personalized cold email to a recruiter.

**Job Details:**
- Title: {{ $json['Job Title'] }}
- Company: {{ $json.Company }}
- Recruiter: {{ $json['Recruiter Name'] || 'Hiring Manager' }}
- Location: {{ $json.Location }}
- Apply URL: {{ $json['Apply URL'] }}

**Candidate Profile:**
- Name: {{ $('User Config').item.json.name }}
- Current Role: {{ $('User Config').item.json.currentRole }}
- Experience: {{ $('User Config').item.json.experience }}
- Skills: {{ $('User Config').item.json.skills.join(', ') }}
- Location: {{ $('User Config').item.json.location }}

**Requirements:**
1. Professional, concise (150-200 words)
2. Show genuine interest in the company/role
3. Highlight 2-3 relevant skills
4. Include a clear call-to-action
5. End with "Best regards, {{ $('User Config').item.json.name }}"

**Format:**
Subject: [Generate compelling subject line]

[Email body]

Provide ONLY the subject line and email body. No additional commentary.

parameters.jsCode:
// Parse Groq email response
const jobData = items[0].json;
const groqResponse = $node["Groq Generate Email"].json.response || $node["Groq Generate Email"].json.text || '';

let subject = `Application for ${jobData['Job Title']} at ${jobData.Company}`;
let body = groqResponse;

// Try to extract subject line
const subjectMatch = groqResponse.match(/Subject:\s*(.+?)\n/i);
if (subjectMatch) {
  subject = subjectMatch[1].trim();
  body = groqResponse.replace(/Subject:\s*.+?\n/i, '').trim();
}

// Add signature if not present
if (!body.includes($('User Config').item.json.name)) {
  body += `\n\nBest regards,\n${$('User Config').item.json.name}`;
}

// Add links
const config = $('User Config').item.json;
body += `\n\nPortfolio: ${config.portfolioUrl}`;
body += `\nLinkedIn: ${config.linkedinUrl}`;
body += `\nGitHub: ${config.githubUrl}`;
body += `\nResume: ${config.resumeUrl}`;

return [{
  json: {
    ...jobData,
    emailSubject: subject,
    emailBody: body,
    sentDate: new Date().toISOString().split('T')[0]
  }
}];

// Update status and add metadata
const applicationId = `EMAIL-${Date.now()}-${Math.random().toString(36).substr(2, 6)}`;

return [{
  json: {
    ...items[0].json,
    Status: 'Email Sent',
    'Application ID': applicationId,
    'Email Sent Date': new Date().toISOString().split('T')[0],
    'Last Updated': new Date().toISOString().split('T')[0]
  }
}];

// Aggregate sending summary
const jobs = items.map(item => item.json);
const total = jobs.length;

const sentList = jobs.map(j => 
  `• **${j['Job Title']}** at **${j.Company}** → ${j['Recruiter Email']}`
);

return [{
  json: {
    total,
    sentList: sentList.join('\n'),
    date: new Date().toISOString().split('T')[0]
  }
}];

